<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Ubuntu", sans-serif;
            overflow: hidden;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            display: flex;
            flex-direction: column;
            background: linear-gradient(135deg, #1a1a2e 0%, #2a2a3e 100%);
            position: relative;
        }

        #taskbar {
            display: flex;
            gap: 10px;
            padding: 8px 12px;
            background: #0a0e27;
            border-top: 1px solid #333;
            height: 50px;
            align-items: center;
            position: relative;
            z-index: 100;
            margin-top: auto;
        }

        .launcher {
            padding: 8px 16px;
            background: #1e1e2e;
            border: 1px solid #444;
            border-radius: 4px;
            color: #e0e0e0;
            cursor: pointer;
            transition: background 0.2s;
            font-size: 14px;
            font-family: inherit;
        }

        .launcher:hover {
            background: #2a2a3e;
        }

        .launcher:active {
            background: #151520;
        }

        .window {
            position: absolute;
            display: none;
            background: #1e1e2e;
            border: 1px solid #444;
            border-radius: 6px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            z-index: 10;
        }

        .window.open {
            display: flex;
        }

        .window-title {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 10px 12px;
            background: #2a2a3e;
            border-bottom: 1px solid #444;
            cursor: move;
            border-radius: 6px 6px 0 0;
            user-select: none;
            flex-shrink: 0;
        }

        .window-title-text {
            color: #e0e0e0;
            font-weight: 500;
        }

        .win-close {
            width: 30px;
            height: 30px;
            background: none;
            border: none;
            color: #e0e0e0;
            cursor: pointer;
            font-size: 18px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: background 0.2s;
            border-radius: 4px;
            font-family: inherit;
        }

        .win-close:hover {
            background: #d94c3b;
        }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 12px;
            color: #e0e0e0;
            display: flex;
            flex-direction: column;
            gap: 0;
        }

        #files-window {
            width: 500px;
            height: 400px;
            top: 100px;
            left: 100px;
        }

        #notepad-window {
            width: 600px;
            height: 450px;
            top: 150px;
            left: 200px;
        }

        #files-path {
            padding: 8px 12px;
            background: #151520;
            border: 1px solid #444;
            border-radius: 3px;
            font-family: monospace;
            font-size: 13px;
            color: #60d9f0;
            margin-bottom: 8px;
            flex-shrink: 0;
        }

        #files-up {
            padding: 8px 12px;
            background: #2a2a3e;
            border: 1px solid #444;
            border-radius: 3px;
            color: #e0e0e0;
            cursor: pointer;
            font-size: 13px;
            margin-bottom: 8px;
            flex-shrink: 0;
            font-family: inherit;
        }

        #files-up:hover {
            background: #353540;
        }

        #files-list {
            display: flex;
            flex-direction: column;
            gap: 2px;
            overflow: auto;
            flex: 1;
        }

        .fs-item {
            padding: 8px 12px;
            cursor: pointer;
            border-radius: 3px;
            transition: background 0.15s;
            user-select: none;
            color: #e0e0e0;
            font-size: 13px;
            flex-shrink: 0;
        }

        .fs-item:hover {
            background: #2a2a3e;
        }

        .fs-item.folder::before {
            content: "📁 ";
            margin-right: 4px;
        }

        .fs-item.file::before {
            content: "📄 ";
            margin-right: 4px;
        }

        #tabs {
            display: flex;
            gap: 4px;
            padding: 8px 12px;
            border-bottom: 1px solid #444;
            background: #151520;
            overflow-x: auto;
            flex-shrink: 0;
            flex-wrap: nowrap;
        }

        .tab {
            padding: 6px 12px;
            background: #2a2a3e;
            border: 1px solid #444;
            border-radius: 4px 4px 0 0;
            color: #a0a0a0;
            cursor: pointer;
            transition: all 0.2s;
            user-select: none;
            white-space: nowrap;
            font-family: inherit;
            font-size: 13px;
            flex-shrink: 0;
        }

        .tab.active {
            background: #1e1e2e;
            color: #e0e0e0;
            border-bottom-color: #1e1e2e;
        }

        .tab:hover {
            background: #303040;
        }

        #new-tab {
            padding: 6px 12px;
            background: #2a2a3e;
            border: 1px solid #444;
            border-radius: 4px 4px 0 0;
            color: #a0a0a0;
            cursor: pointer;
            font-size: 18px;
            height: 30px;
            width: 30px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            font-family: inherit;
            flex-shrink: 0;
        }

        #new-tab:hover {
            background: #303040;
        }

        #editor {
            flex: 1;
            padding: 12px;
            background: #1e1e2e;
            border: none;
            color: #e0e0e0;
            font-family: "Courier New", monospace;
            font-size: 13px;
            resize: none;
            outline: none;
        }

        .notepad-content {
            display: flex;
            flex-direction: column;
            flex: 1;
            gap: 0;
            overflow: hidden;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <div id="taskbar">
            <button id="open-files" class="launcher">📁 Files</button>
            <button id="open-notepad" class="launcher">📝 Notepad</button>
        </div>

        <div id="files-window" class="window">
            <div class="window-title">
                <span class="window-title-text">Files</span>
                <button class="win-close">✕</button>
            </div>
            <div class="window-content">
                <div id="files-path">/</div>
                <button id="files-up">↑ Up</button>
                <div id="files-list"></div>
            </div>
        </div>

        <div id="notepad-window" class="window">
            <div class="window-title">
                <span class="window-title-text">Notepad</span>
                <button class="win-close">✕</button>
            </div>
            <div class="notepad-content">
                <div id="tabs"></div>
                <textarea id="editor" placeholder="Start typing..."></textarea>
            </div>
        </div>
    </div>

    <script>
        const filesystem = {
            '/': {
                'bin': {},
                'etc': {},
                'home': {
                    'user': {
                        'Documents': {
                            'resume.txt': 'file',
                            'notes.txt': 'file'
                        },
                        'Downloads': {
                            'image.png': 'file',
                            'document.pdf': 'file'
                        },
                        'Pictures': {
                            'photo1.jpg': 'file',
                            'photo2.jpg': 'file'
                        }
                    }
                },
                'usr': {},
                'var': {}
            }
        };

        let currentPath = '/';

        function getPathContents(path) {
            const parts = path.split('/').filter(p => p);
            let current = filesystem['/'];

            for (const part of parts) {
                if (current[part]) {
                    current = current[part];
                } else {
                    return {};
                }
            }

            return current;
        }

        function renderFileList() {
            const contents = getPathContents(currentPath);
            const list = document.getElementById('files-list');
            list.innerHTML = '';

            const entries = Object.entries(contents);
            entries.sort((a, b) => {
                const aIsFolder = typeof a[1] === 'object';
                const bIsFolder = typeof b[1] === 'object';
                if (aIsFolder !== bIsFolder) return bIsFolder - aIsFolder;
                return a[0].localeCompare(b[0]);
            });

            for (const [name, content] of entries) {
                const item = document.createElement('div');
                item.className = 'fs-item ' + (typeof content === 'object' ? 'folder' : 'file');
                item.textContent = name;

                if (typeof content === 'object') {
                    item.addEventListener('dblclick', () => {
                        currentPath = (currentPath === '/' ? '/' : currentPath + '/') + name;
                        document.getElementById('files-path').textContent = currentPath;
                        renderFileList();
                    });
                }

                list.appendChild(item);
            }
        }

        document.getElementById('files-up').addEventListener('click', () => {
            if (currentPath !== '/') {
                currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
                document.getElementById('files-path').textContent = currentPath;
                renderFileList();
            }
        });

        let tabs = JSON.parse(localStorage.getItem('notepad-tabs')) || [];
        let activeTab = localStorage.getItem('notepad-active') || null;

        if (tabs.length === 0) {
            tabs = [{ id: 'tab-0', name: 'Untitled 1', content: '' }];
            activeTab = 'tab-0';
        }

        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';

            for (const tab of tabs) {
                const tabEl = document.createElement('div');
                tabEl.className = 'tab' + (tab.id === activeTab ? ' active' : '');
                tabEl.textContent = tab.name;
                tabEl.addEventListener('click', () => switchTab(tab.id));
                tabsContainer.appendChild(tabEl);
            }

            const newTabBtn = document.createElement('button');
            newTabBtn.id = 'new-tab';
            newTabBtn.textContent = '+';
            newTabBtn.addEventListener('click', createNewTab);
            tabsContainer.appendChild(newTabBtn);
        }

        function createNewTab() {
            const newId = 'tab-' + Date.now();
            const newName = 'Untitled ' + (tabs.length + 1);
            tabs.push({ id: newId, name: newName, content: '' });
            activeTab = newId;
            saveTabs();
            renderTabs();
            updateEditor();
        }

        function switchTab(tabId) {
            const currentTabIndex = tabs.findIndex(t => t.id === activeTab);
            if (currentTabIndex !== -1) {
                tabs[currentTabIndex].content = document.getElementById('editor').value;
            }

            activeTab = tabId;
            saveTabs();
            renderTabs();
            updateEditor();
        }

        function updateEditor() {
            const tab = tabs.find(t => t.id === activeTab);
            const editor = document.getElementById('editor');
            editor.value = tab ? tab.content : '';
        }

        function saveTabs() {
            const currentTabIndex = tabs.findIndex(t => t.id === activeTab);
            if (currentTabIndex !== -1) {
                tabs[currentTabIndex].content = document.getElementById('editor').value;
            }
            localStorage.setItem('notepad-tabs', JSON.stringify(tabs));
            localStorage.setItem('notepad-active', activeTab);
        }

        document.getElementById('editor').addEventListener('input', saveTabs);

        document.getElementById('open-files').addEventListener('click', () => {
            document.getElementById('files-window').classList.add('open');
            renderFileList();
        });

        document.getElementById('open-notepad').addEventListener('click', () => {
            document.getElementById('notepad-window').classList.add('open');
            renderTabs();
            updateEditor();
        });

        document.querySelectorAll('.win-close').forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.target.closest('.window').classList.remove('open');
            });
        });

        function makeWindowDraggable(windowEl) {
            const titleBar = windowEl.querySelector('.window-title');
            let offsetX = 0, offsetY = 0, isDragging = false;

            titleBar.addEventListener('mousedown', (e) => {
                if (e.target.closest('.win-close')) return;
                isDragging = true;
                const rect = windowEl.getBoundingClientRect();
                offsetX = e.clientX - rect.left;
                offsetY = e.clientY - rect.top;

                function moveMouse(e) {
                    if (!isDragging) return;
                    windowEl.style.left = Math.max(0, e.clientX - offsetX) + 'px';
                    windowEl.style.top = Math.max(0, e.clientY - offsetY) + 'px';
                }

                function stopMove() {
                    isDragging = false;
                    document.removeEventListener('mousemove', moveMouse);
                    document.removeEventListener('mouseup', stopMove);
                }

                document.addEventListener('mousemove', moveMouse);
                document.addEventListener('mouseup', stopMove);
            });
        }

        makeWindowDraggable(document.getElementById('files-window'));
        makeWindowDraggable(document.getElementById('notepad-window'));

        renderFileList();
        renderTabs();
        updateEditor();
    </script>
</body>
</html>
